val stats = rasterRDD.map { tile =>
  var defined = 0L
  var total = 0L
  var j = tile.y1
  while (j <= tile.y2) {
    var i = tile.x1
    while (i <= tile.x2) {
      if (tile.isDefined(i, j)) {
        defined += 1
      }
      total += 1
      i += 1
    }
    j += 1
  }
  (defined, total)
}.reduce((a, b) => (a._1 + b._1, a._2 + b._2))

